def calc(expr):
    def tokenize(s):
        tokens = []
        i = 0
        while i < len(s):
            if s[i].isspace():
                i += 1
            elif s[i].isdigit():
                j = i
                while j < len(s) and s[j].isdigit():
                    j += 1
                tokens.append(s[i:j])
                i = j
            elif s[i] == '-':
                j = i
                while j < len(s) and s[j].isdigit():
                    j += 1
                tokens.append(s[i:j])
                i = j
            elif s[i] in '()+*/':
                tokens.append(s[i])
                i += 1
            else:
                raise ValueError(f"Invalid character: {s[i]}")
        return tokens

    def parse(tokens, idx):
        if not tokens:
            return None, idx
        val, idx = parse_factor(tokens, idx)
        while idx < len(tokens) and tokens[idx] in ('+', '-'):
            op = tokens[idx]
            idx += 1
            if idx >= len(tokens):
                break
            right, idx = parse_factor(tokens, idx)
            if op == '+':
                val = (val + right)
            else:
                val = (val - right)
        while idx < len(tokens) and tokens[idx] in ('*', '/'):
            op = tokens[idx]
            idx += 1
            if idx >= len(tokens):
                break
            right, idx = parse_factor(tokens, idx)
            if op == '*':
                val = (val * right)
            else:
                val = (val // right)
        return val, idx

    def parse_factor(tokens, idx):
        if idx >= len(tokens):
            return None, idx
        if tokens[idx] == '(':
            idx += 1
            val, idx = parse(tokens, idx)
            if idx < len(tokens) and tokens[idx] == ')':
                idx += 1
            return val, idx
        elif tokens[idx] == '-':
            idx += 1
            val, idx = parse_factor(tokens, idx)
            if val is None:
                return None, idx
            return -val, idx
        elif tokens[idx].isdigit():
            num = int(tokens[idx])
            idx += 1
            return num, idx
        else:
            return None, idx

    tokens = tokenize(expr)
    result, _ = parse(tokens, 0)
    return result

