    return state

def execute_repeat(n, commands, state):
    for _ in range(n):
        for cmd in commands:
            if cmd == 'MOVE':
                x, y, dir, pen = state['x'], state['y'], state['dir'], state['pen']
                state['x'] = x + dir
                state['y'] = y
            elif cmd == 'TURN':
                dir = state['dir']
                state['dir'] = (dir + 1) % 4
            elif cmd == 'DRAW':
                state['pen'] = True
            elif cmd == 'ERASE':
                state['pen'] = False
            elif cmd == 'RESET':
                state['x'] = 0
                state['y'] = 0
                state['dir'] = 1
                state['pen'] = True
    return state

def run_turtle(program):
    def parse_program(program):
        return program.split()

    def execute_command(cmd, state):
        x, y, direction, pen_down, marks = state
        if cmd == "PENDOWN":
            return (x, y, direction, True, marks)
        elif cmd == "PENUP":
            return (x, y, direction, False, marks)
        elif cmd == "MOVE":
            n = int(cmd.split()[1])
            for _ in range(n):
                if pen_down:
                    marks.add((x, y))
                if direction == 0:
                    y += 1
                elif direction == 1:
                    x += 1
                elif direction == 2:
                    y -= 1
                elif direction == 3:
                    x -= 1
            return (x, y, direction, pen_down, marks)
        elif cmd == "TURN L":
            return (x, y, (direction - 1) % 4, pen_down, marks)
        elif cmd == "TURN R":
            return (x, y, (direction + 1) % 4, pen_down, marks)
        else:
            raise ValueError(f"Unknown command: {cmd}")

    def execute_repeat(n, commands, state):
        for _ in range(n):
            for cmd in commands:
                state = execute_command(cmd, state)
        return state

    def run(commands):
        x, y, direction, pen_down, marks = 0, 0, 0, False, set()
        i = 0
        while i < len(commands):
            cmd = commands[i]
            if cmd == 'REPEAT':
                n = int(commands[i+1])
                start_idx = i + 2
                end_idx = len(commands)
                while start_idx < end_idx and commands[start_idx] != ']':
                    start_idx += 1
                inner_cmds = commands[start_idx+1:end_idx]
                state = execute_repeat(n, inner_cmds, (x, y, direction, pen_down, marks))
                x, y, direction, pen_down, marks = state
                i = end_idx
            else:
                state = execute_command(cmd, (x, y, direction, pen_down, marks))
                x, y, direction, pen_down, marks = state
                i += 1
        return (x, y, sorted(list(marks)))

    tokens = parse_program(program)
    return run(tokens)
